var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"갑자기 나타나서 뭐 하는 거야? 제삼자는 빠지라고!","JPN":"突然現れて何なの！？　第三者は引っ込んでなさいよ！","ENG":"Mind your own business, okay?! Stay out of this!","TWN":"突然冒出來是要幹嘛？局外人就別攪和了！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STAR_LEGACY_NULL_QM","text":{"KOREA":"쯔쯧! 그라믄 안 돼 그라믄.","JPN":"ちっちっ……そんなんあかん、そんなん。","ENG":"Tsk, tsk! That ain't right.","TWN":"嘖嘖！這可不行，一點都不行。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_LEGACY_NULL_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"STAR_LEGACY_NULL_QM","text":{"KOREA":"퀘스트는 서로 사이좋게 해야지, 싸우기나 하고 그라믄 안 돼.","JPN":"クエストはケンカせんと、互いに仲ようやらなあかんねん。","ENG":"Y'all should be workin' together to beat the quest, not fightin' each other.","TWN":"任務要和和氣氣地完成，不可以吵架。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_LEGACY_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"그러니까 이 미리네 님한테 싱겁게 패배하는 거 아니겠나?","JPN":"そんなんやからこのマリ様にあっさり負けるんやで。","ENG":"Ain't that why y'all lost to me, Mi Rinae?","TWN":"所以才會輕易地敗給我宓璃奈吧？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L8_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"미리네……? 잠깐, 패배했다고?","JPN":"マリ……？　ちょっと、負けるですって！？","ENG":"Mi Rinae...? Hold on, what do you mean we lost?","TWN":"宓璃奈……？等等，輸了？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"스카이 녀석들을 어쩐거야?!","JPN":"スカイたちはどうしたの！？","ENG":"What did you do to Sky and the others?!","TWN":"你對絲凱她們做了什麼？！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"얘, 얘는 구해줬더니 보따리 내놓으라 카네?","JPN":"こ、この子……助けてやったのに恩知らずやなあ。","ENG":"I just saved their butts and all I get in return is ya shouting at my face?","TWN":"喂，我都救了這傢伙，還要我交出寶箱？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"진정해요 선배! 미리네 씨는 저흴 구해주신 거예요!","JPN":"落ち着いて、先輩！　マリさんは私たちを助けてくれたんです！","ENG":"Calm down, Naielle! Mi Rinae's the one who saved us!","TWN":"冷靜點，前輩！宓璃奈姊姊是來救我們的！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"보물 상자가 갑자기 괴물로 변할 줄은 몰랐어요…….","JPN":"宝箱が急に化け物に変身するとは思わなかった……","ENG":"We didn't know the chest would suddenly transform into a monster...","TWN":"沒想到寶箱突然變成了怪物……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그, 그럼 설마…….","JPN":"じゃ、じゃあまさか……","ENG":"Th-then...","TWN":"那，那難道……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아하하, 뭐 그렇게 됐다.","JPN":"あはは、まあ。そんなもんや。","ENG":"Ah hah hah. Well, ain't that the truth.","TWN":"哈哈哈，反正就是這樣的。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아! 뺏은 건 아니고, 아까 그 미믹한텐 아무것도 안 나왔다.","JPN":"あ！　奪ったんちゃうで。さっきのミミックからは何も出んかった。","ENG":"Oh, and by the way! I didn't steal nothin'. The mimic didn't even drop a thing.","TWN":"啊！不是我拿的，剛才那個怪物什麼都沒掉。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"어쨌든 이번 퀘스트의 승자는 이 미리네가 됐다 이 말이다.","JPN":"とにかく、今回のクエストの勝者はこのマリ様っちゅうわけや。","ENG":"Anywho, the winner of this quest is me, Mi Rinae.","TWN":"總之，這次任務的贏家是我，宓璃奈。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L22_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이, 이렇게 허무하게……?","JPN":"こ、こんなにあっけなく……","ENG":"S-so this is how it ends...?","TWN":"這，這麼空虛……？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아하하, 너무 그렇게 상심하지 마라.","JPN":"あはは、そんなへこまんといて。","ENG":"Ah hah hah! Now, don't be so discouraged.","TWN":"哈哈哈，不要那麼傷心。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"니 아카데미 학생 맞제? 이름이 뭐꼬?","JPN":"あんた、アカデミーの生徒やろ？　名前なんて言うん？","ENG":"You're from the Academy, aren't ya? What's your name?","TWN":"你是學院的學生吧？你叫什麼名字？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"흥, 엘리트인 내 이름을 모르는 게 말이 돼?","JPN":"ふん、エリートの私の名前を知らないなんてあり得ないんだけど。","ENG":"Hmph. How can anyone not know an elite like me?","TWN":"哼，不知道我這個精英的名字，怎麼可能？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"엘리트……?","JPN":"エリート……？","ENG":"Elite...?","TWN":"精英……？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아~ 니 설마 나이엘이가? 나이엘 블루스틸! 맞제?!","JPN":"ああ～まさかあんたナイエル？　ナイエル・ブルースチール！　そうやろ？","ENG":"Oh! You're the Naielle gal, ain't ya? Naielle Bluesteel! Right?!","TWN":"啊～你該不會是奈爾吧？奈爾·布魯斯提爾，對吧？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"하핫, 거 봐! 역시 알고 있었잖아!","JPN":"ふん！　ほら、やっぱり知ってるじゃない！","ENG":"Haha! So you do know who I am!","TWN":"哈哈，你看！果然知道吧！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"……아니, 어떻게 알고 있는 거야?","JPN":"……って、どうして知ってるのよ？","ENG":"...Wait. How did you know?","TWN":"……不，不對，你是怎麼知道的？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"네가 그 나이엘이구나! 보라한테 말 많이 들었다!","JPN":"あんたがあのナイエルか～！　シホから話は聞いたで！","ENG":"We finally meet in person, Naielle! I heard a lot 'bout ya from Bora!","TWN":"你就是那個奈爾啊！聽寶拉說了很多關於你的事！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"우리 나름 구면인데, 내 못 알아보긋나?","JPN":"ウチら、実は初対面ちゃうけど、ウチのこと知らへん？","ENG":"We've met before; can't ya recognize me?","TWN":"我們以前見過的，你不記得我了嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"뭐야, 당신 그 낙하산이랑 아는 사이였어? 난 당신 본 기억 없다고!","JPN":"何よ、あんたあのコネ教師と知り合い？　私は見覚えないんだけど。","ENG":"Huh? You're friends with her? I've never seen you in my life!","TWN":"什麼，你和那個空降部隊認識？我可不記得見過你！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"흠…… 그래?\xA0","JPN":"ふーん……そう？\xA0","ENG":"Hmm... Is that so?\xA0","TWN":"嗯……是嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"그럼 오락실의 랭커★스타라이트! 이러면 알긋제?","JPN":"じゃ、ゲームセンターのランカー★スターライト！　って言うたらわかるかな？","ENG":"Then, how 'bout the arcade's Ranker★Starlight! Does that ring a bell?","TWN":"遊藝場的高手★星光！這樣就知道了吧？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ONLY_GAMECIRCLE_C_STAR_HYPER_ATTACK_END"},{"id":"L45_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"어……? 설마 당신이 그 유명하다는 사람?!","JPN":"え……？　まさか、あんたがあの有名な？","ENG":"Huh...? You're the famous person?!","TWN":"遊藝場的高手★星光！這樣就知道了吧？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아하하, 보라가 그렇게 말하드나, 걔도 참 그러지 말라니까 그러네.","JPN":"あはは、シホがそんなふうに言うとったんか。あの子ったらまったく。","ENG":"Ah hah hah! Is that what Bora told ya? I told her not to 'cause it's embarrassing.","TWN":"哈哈，寶拉是這麼說的。她也真是的，叫她別那麼說了。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"저기, 미리네라고 하셨죠? 인터뷰 가능할까요?","JPN":"あの、マリさんですよね？　インタビュー大丈夫でしょうか？","ENG":"Um, Mi Rinae, was it? Would you be willing to participate in an interview?","TWN":"那個，你是宓璃奈吧？可以接受採訪嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"오?! 하트베리의 미야 씨 맞죠?","JPN":"お！？　ハートベリーのミヤさんやんか！","ENG":"Oh?! Aren't ya Miya from HRT Berry?","TWN":"喔？！你是愛心莓果的米婭吧？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아하하, 방송 잘 보고 있습니다. 실물로 보니까 훨~씬 이쁘시네요!","JPN":"配信、よく見とるで。実物のほうがずーっときれいやな！","ENG":"Ah hah hah! I'm a huge fan. You look so much prettier in person!","TWN":"哈哈哈，我一直在看你的直播。見到真人後，發現你本人漂亮多了！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L4_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"으아아~ 악수하시는 건 좋은데, 너무 세게 흔드세요……!","JPN":"わああ～握手はいいけど強く振りすぎです……！","ENG":"Whoa...! I don't mind handshakes, but I feel like my arm is about to fall off...!","TWN":"啊啊～你握得有點太用力了……～"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"어이 어이, 우릴 완전히 잊어버린 거 아냐?","JPN":"ちょっと、私たちのこと忘れてないか？","ENG":"Hey, hey. Did you totally forget about us?","TWN":"喂喂，不會把我們忘了吧？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L7_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"승부 도중에 방해를 받으면 조금 열 받을지도 모른다고?","JPN":"勝負の途中で邪魔されたら困るんだが？","ENG":"It's a bit upsetting that our fight was interrupted.","TWN":"你不知道關鍵時刻被打擾，這會很讓人生氣嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BLOOD_LEGACY_NULL_EXTRAA","text":{"KOREA":"잠깐! 우린 파티원이 이렇게나 많은데도 안 나오던데……?","JPN":"待て！　こっちはこんな大人数で探してもまったくアイテムが見つからなかったのに……？","ENG":"Wait! We have this many party members, and we still couldn't find it...","TWN":"等一下！我們隊伍裡有這麼多人，怎麼還沒找到……？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BLOOD_LEGACY_NULL_EXTRAA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BLOOD_LEGACY_NULL_EXTRAB","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"BLOOD_LEGACY_NULL_EXTRAB","text":{"KOREA":"브로마이드 어떤 사진이에요? 제발 한 번만 보여주세요!","JPN":"ブロマイド、どんな写真だったんですか？　お願いします。一度でいいから拝ませてください！","ENG":"What photo was on the poster? Could you show it to us?","TWN":"照片是什麼樣子的？拜託，給我看一眼吧！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BLOOD_LEGACY_NULL_EXTRAA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BLOOD_LEGACY_NULL_EXTRAB","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"시끄럽다! 니들같이 음흉한 녀석들에겐 절~대 안보여줄 기다!","JPN":"うっさいわ！　あんたらみたいなやらしい奴らには絶対見せへん！","ENG":"Quit your yappin'! I ain't showin' nothin' to sneezy pricks like you!","TWN":"吵死了！像你們這種卑鄙的傢伙，絕～對不會給你們看的！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"니들 방송 제대로 본 거 맞나? 그게 몬스터한테만 뜬다 카든?","JPN":"ホンマ、ちゃんと配信見とったんか？　モンスターのドロップやなんて一度も言うてへんかったで。","ENG":"Did y'all even watch the stream? They never said it'd appear by defeating a monster.","TWN":"你們真的看了直播嗎？那只會對怪物顯示嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"이 퀘스트는 일종의 보물찾기, 보물찾기는 쟁탈전이다.","JPN":"このクエストは一種の宝探しや。宝探しっちゅうのは、すなわち争奪戦やねん。","ENG":"This here quest was a good ol' treasure hunt. And treasure hunts are finders keepers, y’all.","TWN":"這個任務就像是尋寶遊戲。尋寶嘛，就是一種爭奪戰。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"느그들끼리 싸우는 덕에, 내는 편하게 찾을 수 있었다 이 말이다.","JPN":"あんたたちがケンカに夢中になっとってくれたおかげで、ウチは探すのが楽勝やったわ。","ENG":"Thanks to your fightin', I was able to easily get my hands on it.","TWN":"多虧了你們自己打起來，我才能輕鬆找到這裡。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"아, 아무리 그래도 몬스터에게서 단 한 개도 나오지 않은 건 이상하잖아요!","JPN":"だ、だとしてもモンスターから1個も出なかったのはおかしいです！","ENG":"B-but still. It's weird that not even a single one dropped from the monsters!","TWN":"啊，不管怎麼說，怪物身上什麼都沒掉出來，這也太奇怪了吧！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"사기야…… 이 퀘스트는 유저 기만이에요!","JPN":"詐欺だ……このクエストは詐欺です！","ENG":"This is a scam... This quest was made to trick us!","TWN":"騙人……這個任務就是在欺騙玩家！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"미야 씨! 왜 제대로 말을 안 해줬어요?!","JPN":"ミヤさん！　なんで詳しく説明してくれなかったんですか！？","ENG":"Miya! Why didn't you tell us the full details?!","TWN":"米婭小姐！為什麼不跟我們好好說清楚？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"제가 의도한 건 여러분에게 조금씩 힌트를 줘가면서 서로 협력하는 거였는데…….","JPN":"私は少しずつヒントを与えて、皆さんが協力して探しだす流れを想定していたんですけど……","ENG":"What I intended was to give out tiny hints so you'd all cooperate with each other...","TWN":"我本來是想給你們一點點提示，讓大家互相合作的……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"그런데 갑자기 여러분들끼리 싸우시는 바람에…….","JPN":"急に皆さんが戦い出しちゃって……","ENG":"But you all suddenly started fighting, and...","TWN":"但是突然之間你們自己打起來了……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"그런가…… 나는 동료만 많았지, 통솔하는 능력은 한 참 부족했군.","JPN":"そうか……私は大勢の仲間を持ちながらも、それを率いる能力に欠けていたということか……","ENG":"I see... I had many comrades, but I lacked the ability to lead them.","TWN":"是嗎……我雖然有很多同伴，但領導能力還是遠遠不足。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"훗훗훗. 반성하지! 다음엔 더 성장해서 돌아오겠다!","JPN":"フッフッフ、反省しよう！　次はもっと成長した姿で戻って来る！","ENG":"Hah hah hah. I've learned my lesson! I shall return a changed woman next time!","TWN":"哼哼哼，我好好反省一下！下次我會變得更強再回來！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L30_1","type":"dialog","speaker":"BLOOD_LEGACY_NULL_EXTRAA","text":{"KOREA":"성장하긴 뭘 성장해요? 우린 여기서 끝입니다!","JPN":"成長も何もないでしょう！　私たちはここで終わりです！","ENG":"What do you mean, \\"next time\\"? This is it for us!","TWN":"變強個鬼！我們緣分已盡！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BLOOD_LEGACY_NULL_EXTRAA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BLOOD_LEGACY_NULL_EXTRAB","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"……엥?","JPN":"……え？","ENG":"...Huh?","TWN":"……嗯？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BLOOD_LEGACY_NULL_EXTRAB","text":{"KOREA":"맞아요! 브로마이드도 못 얻고, 이 파티는 이제 아무 의미 없어요!","JPN":"そうです！　ブロマイドも見つからなかったし、このパーティーにはもう何の意味もない！","ENG":"He's right! This party's lost its meaning without the poster!","TWN":"沒錯！連海報都沒拿到，這個隊伍已經毫無意義了！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BLOOD_LEGACY_NULL_EXTRAA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BLOOD_LEGACY_NULL_EXTRAB","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"XIEN_FREEDOM_NULL_NULL","text":{"KOREA":"기, 기다려! 우린 의리로 똘똘 뭉친 혈맹이잖아! 가지 말아줘~","JPN":"ま、待て！　私たちは義理で結ばれた血盟だろう？　行くな～","ENG":"W-wait! But we're bound by blood and loyalty! Don't leave!","TWN":"等，等等！我們可是情同手足的血盟啊！不要走～"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIEN_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L41_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"여, 여러분~ 굉장히 소란스러웠지만, 어쨌든 퀘스트의 승자는 미리네 씨가 되셨어요.","JPN":"み、皆さん～少々お騒がせしましたが、とにかくクエストの勝者はマリさんに決まりました！","ENG":"E-everyone? Although it was very rowdy, the winner of this quest is Mi Rinae.","TWN":"各位～雖然剛才非常吵鬧，但無論如何任務的贏家是宓璃奈！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아하하, 승리 포즈는 여기다 대고 하면 돼요?","JPN":"あはは、勝利ポーズはこっち向いてやったらええん？","ENG":"Ah hah hah! Now, do I do my victory pose here?","TWN":"哈哈哈，慶祝動作是對著這裡做嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L44_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"나, 난 인정 못 해! 내 작전은 완벽했다고!","JPN":"わ、私は認めない！　私の作戦は完璧だったのよ！","ENG":"I-I can't accept this! My plan was perfect!","TWN":"我，我不能接受！我的作戰計畫是完美的！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MIYA_HB_VAL_NULL","text":{"KOREA":"앗, 아직 방송 종료 안 했는데…….","JPN":"あっ、まだ配信終わってないんだけど……","ENG":"Oh, I haven't turned off the livestream yet...","TWN":"啊，直播還沒結束呢……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_VAL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"졌으면 깨끗하게 인정해야지. 엘리트가 그라믄 안 돼.","JPN":"エリートなら潔く負けを認めなあかんで。","ENG":"Can't call yourself an elite if ya can't admit that you lost.","TWN":"輸了就要乾脆地認輸，真正的精英可不是像你這樣的。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"괜찮아요 선배. 꼭 여기서 이겨야만 랭커가 되는 건 아니잖아요?","JPN":"大丈夫ですよ、先輩。ここで勝てなくてもランカーにはなれますし。","ENG":"It's okay, Naielle. This isn't our only chance to become a top ranker.","TWN":"沒關係的，前輩。不一定非要在這裡贏了才能成為高手吧？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"RULER_JUNIOR_NULL_NULL","text":{"KOREA":"다음엔 분명 좋은 기회가 다시 찾아올 거예요!","JPN":"きっとまたチャンスは来ますよ！","ENG":"I'm sure another opportunity will come!","TWN":"下次一定還會有好機會出現的！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"다음에 저희가 도울 수 있는 게 있다면 언제든 불러주세요.","JPN":"次またあたしたちに手伝えることがあったら、いつでも呼んでくださいね。","ENG":"And if there's anything we can help with next time, feel free to call us.","TWN":"如果下次有我們能幫忙的地方，請隨時叫我們來幫忙。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아하하, 여기 귀염둥이 삼총사가 훨씬 더 어른스럽네.","JPN":"あはは、こっちの可愛い3人組のほうがよっぽど大人やな。","ENG":"Ah hah hah. This little trio is far more mature than ya.","TWN":"哈哈哈，她們可愛三人組感覺比你還成熟呢。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"니들은 나중에 크면 무조건 크게 될 기다. 열심히들 해라.","JPN":"あんたたちはきっと素晴らしい大人になるで。これからも頑張りや。","ENG":"Y'all are gonna grow up to be successful. Keep up the good work.","TWN":"你們以後長大了肯定會有出息的。加油吧。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"하~ 그럼 어쩔 수 없네.","JPN":"はあ～しゃあないな。","ENG":"*Sigh* I shouldn't, but...","TWN":"哈～那就沒辦法了。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"니가 너무 상심하는 것 같으니께, 내가 좋은 정보 하나 줄게.","JPN":"あんたがあまりにもへこんでるみたいやから、ええ情報を教えたるわ。","ENG":"Since ya seem so upset 'bout losin', I'll give ya a lil' tip.","TWN":"看你這麼傷心，我告訴你一個好消息吧。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"……일단 말해 봐.","JPN":"……何よ。","ENG":"...Let's hear it.","TWN":"……先說說看。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"정 그렇게 랭킹을 올리고 싶으면, <color=#ffd34c>카운터즈 토너먼트</color>에 함 참가해 봐라.","JPN":"そんなにランキング上げたいんやったら、<color=#ffd34c>カウンターズ・トーナメント</color>に参加したらええよ。","ENG":"If ya really wanna be a ranker, why don't cha play in that <color=#ffd34c>Counters Tournament</color>?","TWN":"如果你真的想提高排名，就去參加<color=#ffd34c>制裁者淘汰賽</color>吧。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"뭐야 그건……?","JPN":"何それ……？","ENG":"What's that...?","TWN":"那是什麼……？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"유저들끼리 대결하면서 경쟁하는 컨텐츠 말이다. 그게 랭킹 반영에 그렇게 잘된다더라.","JPN":"ユーザー同士で対決するコンテンツや。ランキング上げにあれほど効果的なもんはないらしいで。","ENG":"It's a tournament where players compete with each other. I heard it's good for climbing up the ranks.","TWN":"就是玩家之間的競爭，聽說會影響排名。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"보라는 그런 거엔 쫌 회의적이긴 한데, 옆에 있는 애 입지도 무시할 순 없었던 것 같다.","JPN":"シホはあんまり乗り気じゃなかったみたいやけど、一緒にいる子の意思が強くてな、無視できんかったみたいやで。","ENG":"Bora's a lil skeptical 'bout it, but I guess she couldn't turn a blind eye to that kid next to her.","TWN":"雖然寶拉對此有些懷疑，但也不能忽視旁邊那傢伙的立場。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그 땅꼬마를 말하는 거야? 그 녀석이 그렇게 대단하다고?","JPN":"あのチビのこと……？　あいつがそんなに偉いの？","ENG":"Are you talking about that pipsqueak? Is she really that influential?","TWN":"你是說那個矮冬瓜嗎？那傢伙有那麼厲害嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"어때? 흥미 있나?","JPN":"どう？　興味ある？","ENG":"So? Are ya interested?","TWN":"怎麼樣？有興趣嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"……흥이다! 내가 당신 말을 믿을 줄 알고?","JPN":"……ふん！　誰があんたの言葉なんか信じるもんですか！","ENG":"...Hmph! Like I'd believe a word you say!","TWN":"……哼！你以為我會相信你說的話嗎？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"내는 알려 줬다. 선택은 니가 하는기다. \xA0","JPN":"ウチはちゃんと教えたで。選択はあんたがするんや。\xA0 ","ENG":"I'm just tellin' ya. It's your choice whether to believe it or not.\xA0","TWN":"我已經告訴你了，選擇在於你。"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"계속 그렇게 풀 죽어 있지 좀 마라. 괜히 신경 쓰이니까!","JPN":"だからそんなしょんぼりすんな。こっちも気になるやんか。","ENG":"Try not to be so discouraged, 'kay? It worries me!","TWN":"別一直那麼垂頭喪氣的，看著還蠻讓人擔心的呢！"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_PROMISE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"니는 아직 젊다! 젊을 땐 다 그런 거 하나하나가 청춘 아니겠나~","JPN":"あんたはまだ若い！　こういう経験も青春のええ思い出になるんやで。","ENG":"You're still young! Ain't youth all 'bout experience?","TWN":"你還年輕！這些都是青春的一部分啊～"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L30_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"나랑 동갑처럼 보이는데, 무슨 애늙은이 같은 말을 하고 있어?","JPN":"私とそう変わらない見た目なのに何老人みたいなこと言ってるのよ？","ENG":"You look the same age as me–why are you talking like some old person?","TWN":"看起來和我同齡，怎麼說話像個小老頭似的？"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};